```class Solution {
    public String largestPalindrome(int n, int k) {
        String res = "";
        for (int i = (int) Math.pow(10, n - 1); i > 0; i--) {
            int num = i;
            int rev = 0;
            while (num > 0) {
                int digit = num % 10;
                num /= 10;
                rev = rev * 10 + digit;
            }
            if (rev * k % i == 0 && i * k % rev == 0) {
                res = String.valueOf(i * k);
                break;
            }
        }
        return res;
    }
}```
